@startuml

package "states" {
  class Originator {
    - state: String
    .. Setter ..
    + setState(state: String): void
    .. Getter ..
    + getState(): String
    .. Other ..
    + saveStateToMemento(): Memento
    + recoverStateFromMemento(memento: Memento): void
  }

  class CareTaker {
    - mementos: List<Memento> = new ArrayList<>()
    .. Other ..
    + add(memento: Memento): void
    + get(index: int): Memento
  }

  class Memento {
    - state: String
    .. Constructor ..
    + Memento(state: String): void
    .. Getter ..
    + getState(): String
  }

  Originator --> Memento
  CareTaker o-- Memento
}

class Client {
  + main(): void
}

Client --> Originator

@enduml
